  ($$wrap_generating$$, $$Writing your story…$$, $$ກຳລັງຂຽນເລື່ອງຂອງເຈົ້າ…$$, $$กำลังเขียนเรื่องราวของคุณ…$$, 'MonthlyWrap'),
  ($$wrap_error$$, $$Couldn't generate your wrap — try again$$, $$ບໍ່ສາມາດສ້າງສະຫຼຸບໄດ້ — ລອງໃໝ່$$, $$สร้างสรุปไม่ได้ — ลองอีกครั้ง$$, 'MonthlyWrap'),
  ($$wrap_timeout$$, $$This took too long ⏳ Please try again$$, $$ໃຊ້ເວລາດົນເກີນໄປ ⏳ ລອງໃໝ່$$, $$ใช้เวลานานเกินไป ⏳ ลองใหม่$$, 'MonthlyWrap'),
  ($$wrap_partial$$, $$Your story is resting, but here are the numbers$$, $$ເລື່ອງຂອງເຈົ້າພັກຜ່ອນຢູ່ ແຕ່ນີ້ຄືຕົວເລກ$$, $$เรื่องราวพักอยู่ แต่นี่คือตัวเลข$$, 'MonthlyWrap'),
  ($$wrap_empty$$, $$Nothing logged this month yet — start adding transactions to unlock your wrap!$$, $$ຍັງບໍ່ມີລາຍການໃນເດືອນນີ້ — ເພີ່ມລາຍການເພື່ອເປີດສະຫຼຸບ!$$, $$ยังไม่มีรายการเดือนนี้ — เพิ่มรายการเพื่อปลดล็อคสรุป!$$, 'MonthlyWrap'),
  ($$wrap_retry$$, $$Try again$$, $$ລອງໃໝ່$$, $$ลองอีกครั้ง$$, 'MonthlyWrap'),
  ($$wrap_total_expense$$, $$Total expenses$$, $$ລວມລາຍຈ່າຍ$$, $$ค่าใช้จ่ายรวม$$, 'MonthlyWrap'),
  ($$wrap_total_income$$, $$Total income$$, $$ລວມລາຍຮັບ$$, $$รายรับรวม$$, 'MonthlyWrap'),
  ($$wrap_top_category$$, $$Top category$$, $$ໝວດສູງສຸດ$$, $$หมวดสูงสุด$$, 'MonthlyWrap'),
  ($$wrap_biggest_day$$, $$Biggest day$$, $$ວັນທີ່ໃຊ້ຈ່າຍຫຼາຍສຸດ$$, $$วันที่ใช้จ่ายมากสุด$$, 'MonthlyWrap'),
  ($$wrap_active_days$$, $$Active days$$, $$ມື້ທີ່ບັນທຶກ$$, $$วันที่บันทึก$$, 'MonthlyWrap'),
  ($$wrap_vs_last$$, $$Vs last month$$, $$ທຽບກັບເດືອນກ່ອນ$$, $$เทียบกับเดือนก่อน$$, 'MonthlyWrap'),
  ($$wrap_close$$, $$Close$$, $$ປິດ$$, $$ปิด$$, 'MonthlyWrap'),
  ($$statementScan$$, $$Bank statement scan$$, $$ສະແກນໃບແຈ້ງຍອດ$$, NULL, 'StatementScan'),
  ($$statementScanSubtitle$$, $$Import transactions from your bank app$$, $$ນຳເຂົ້າທຸລະກຳຈາກແອັບທະນາຄານ$$, NULL, 'StatementScan'),
  ($$statementScanProGate$$, $$Upgrade to Pro to scan bank statements$$, $$ອັບເກຣດເປັນ Pro ເພື່ອສະແກນໃບແຈ້ງຍອດ$$, NULL, 'StatementScan'),
  ($$statementPickCurrency$$, $$Which currency?$$, $$ສະກຸນເງິນຫຍັງ?$$, NULL, 'StatementScan'),
