  ($$statementSuccess$$, $$Imported {n} transactions!$$, $$ນຳເຂົ້າ {n} ທຸລະກຳສຳເລັດ!$$, NULL, 'StatementScan'),
  ($$statementCurrencyMismatch$$, $$Bank shows {detected} but you picked {selected}$$, $$ທະນາຄານສະແດງ {detected} ແຕ່ເຈົ້າເລືອກ {selected}$$, NULL, 'StatementScan'),
  ($$statementCurrencyUseDetected$$, $$Use {detected} (from bank)$$, $$ໃຊ້ {detected} (ຈາກທະນາຄານ)$$, NULL, 'StatementScan'),
  ($$statementCurrencyUseSelected$$, $$Use {selected} (as I picked)$$, $$ໃຊ້ {selected} (ຕາມທີ່ເລືອກ)$$, NULL, 'StatementScan'),
  ($$statementErrorParse$$, $$Couldn't read the screenshots. Try clearer images.$$, $$ອ່ານຮູບບໍ່ໄດ້. ລອງຮູບທີ່ຊັດເຈນກວ່າ.$$, $$อ่านภาพไม่ได้ ลองใช้ภาพที่ชัดกว่า$$, 'StatementScan'),
  ($$statementErrorNetwork$$, $$Network error. Check connection and try again.$$, $$ມີບັນຫາເຄືອຂ່າຍ. ກວດເບິ່ງການເຊື່ອມຕໍ່.$$, $$เครือข่ายมีปัญหา ตรวจสอบการเชื่อมต่อแล้วลองใหม่$$, 'StatementScan'),
  ($$statementErrorTimeout$$, $$Reading images taking too long ⏳ Please try again$$, $$ອ່ານຮູບຊ້າເກີນໄປ ⏳ ລອງໃໝ່$$, $$อ่านภาพนานเกินไป ⏳ ลองใหม่$$, 'StatementScan'),
  ($$statementErrorRateLimit$$, $$Too many requests. Wait a minute and retry.$$, $$ຄຳຂໍເກີນກຳນົດ. ລໍຖ້າ 1 ນາທີ.$$, $$คำขอเกินกำหนด รอ 1 นาทีแล้วลองใหม่$$, 'StatementScan'),
  ($$statementRecentImports$$, $$Recent imports$$, $$ການນຳເຂົ້າຫຼ້າສຸດ$$, $$นำเข้าล่าสุด$$, 'StatementScan'),
  ($$statementImportDetails$$, $$Import details$$, $$ລາຍລະອຽດການນຳເຂົ້າ$$, $$รายละเอียดการนำเข้า$$, 'StatementScan'),
  ($$statementMoreTx$$, $$+{n} more$$, $$+{n} ເພີ່ມ$$, $$+{n} เพิ่ม$$, 'StatementScan'),
  ($$statementDeleteAll$$, $$Delete all ({n})$$, $$ລົບທັງໝົດ ({n})$$, $$ลบทั้งหมด ({n})$$, 'StatementScan'),
  ($$statementNoTx$$, $$No transactions found$$, $$ບໍ່ພົບທຸລະກຳ$$, $$ไม่พบรายการ$$, 'StatementScan'),
  ($$statementNoTxHint$$, $$Try clearer images or a different bank app screenshot$$, $$ລອງອັບໂຫຼດຮູບທີ່ຊັດເຈນກວ່າ ຫຼື ເລືອກທະນາຄານອື່ນ$$, $$ลองใช้ภาพที่ชัดกว่า หรือภาพหน้าจอแอปธนาคารอื่น$$, 'StatementScan'),
  ($$statementDone$$, $$Done$$, $$ສຳເລັດ$$, $$เสร็จ$$, 'StatementScan'),
  ($$analyticsThisWeek$$, $$This Week$$, $$ອາທິດນີ້$$, $$สัปดาห์นี้$$, NULL),
  ($$analyticsVsLastMo$$, $$vs last mo$$, $$ທຽບກັບເດືອນກ່ອນ$$, $$เทียบกับเดือนก่อน$$, NULL),
  ($$settingsPinExplain$$, $$Your password protects your account. A PIN adds quick daily unlock — useful if you share your phone.$$, $$ລະຫັດຜ່ານປົກປ້ອງບັນຊີຂອງທ່ານ. PIN ເພີ່ມການປົດລ໊ອກໄວປະຈຳວັນ — ເໝາະຖ້າແບ່ງປັນໂທລະສັບກັບຄອບຄົວ.$$, $$รหัสผ่านปกป้องบัญชีของคุณ PIN เพิ่มการปลดล็อกเร็วประจำวัน — เหมาะถ้าแชร์โทรศัพท์กับครอบครัว$$, NULL),
  ($$proBackSettings$$, $$← Settings$$, $$← ການຕັ້ງຄ່າ$$, $$← การตั้งค่า$$, NULL),
