  ($$proFeatLogDesc$$, $$Lao, Thai, English$$, $$ລາວ, ໄທ, ອັງກິດ$$, $$ลาว, ไทย, อังกฤษ$$, NULL),
  ($$proFeatAnalytics$$, $$Analytics & budgets$$, $$ວິເຄາະ ແລະ ງົບ$$, $$วิเคราะห์และงบ$$, NULL),
  ($$proFeatAnalyticsDesc$$, $$Charts, MoM comparison$$, $$ກາຟ, ທຽບເດືອນຕໍ່ເດືອນ$$, $$กราฟ, เทียบเดือนต่อเดือน$$, NULL),
  ($$proFeatGoals$$, $$Goals & streaks$$, $$ເປົ້າໝາຍ ແລະ ວັນຕິດຕໍ່ກັນ$$, $$เป้าหมายและวันติดต่อกัน$$, NULL),
  ($$proFeatGoalsDesc$$, $$10 XP levels$$, $$10 ລະດັບ XP$$, $$10 เลเวล XP$$, NULL),
  ($$proFeatPin$$, $$PIN & guest access$$, $$PIN ແລະ ໂໝດແຂກ$$, $$PIN และโหมดแขก$$, NULL),
  ($$proFeatPinDesc$$, $$Share safely with family$$, $$ແບ່ງປັນກັບຄອບຄົວຢ່າງປອດໄພ$$, $$แชร์กับครอบครัวอย่างปลอดภัย$$, NULL),
  ($$proFeatAdvisor$$, $$AI Advisor chat$$, $$ແຊັດກັບ AI Advisor$$, $$แชทกับ AI Advisor$$, NULL),
  ($$proFeatAdvisorDesc$$, $$Personal finance assistant$$, $$ທີ່ປຶກສາການເງິນສ່ວນຕົວ$$, $$ที่ปรึกษาการเงินส่วนตัว$$, NULL),
  ($$proFeatOcr$$, $$Receipt OCR$$, $$ສະແກນໃບບິນ$$, $$สแกนใบเสร็จ$$, NULL),
  ($$proFeatOcrDesc$$, $$Scan & auto-log bills$$, $$ສະແກນ ແລະ ບັນທຶກອັດຕະໂນມັດ$$, $$สแกนและบันทึกอัตโนมัติ$$, NULL),
  ($$proFeatMemory$$, $$AI memory$$, $$ຄວາມຊົງຈຳ AI$$, $$ความจำ AI$$, NULL),
  ($$proFeatMemoryDesc$$, $$Learns your spending habits$$, $$ຮຽນຮູ້ນິໄສການໃຊ້ຈ່າຍຂອງທ່ານ$$, $$เรียนรู้นิสัยการใช้จ่ายของคุณ$$, NULL),
  ($$proFeatExport$$, $$Export CSV / Excel$$, $$ສົ່ງອອກ CSV / Excel$$, $$ส่งออก CSV / Excel$$, NULL),
  ($$proFeatExportDesc$$, $$Download your data anytime$$, $$ດາວໂຫຼດຂໍ້ມູນໄດ້ທຸກເວລາ$$, $$ดาวน์โหลดข้อมูลได้ทุกเวลา$$, NULL),
  ($$proDisclaimer$$, $$Cancel anytime · No hidden fees$$, $$ຍົກເລີກໄດ້ທຸກເວລາ · ບໍ່ມີຄ່າທຳນຽມແອບ$$, $$ยกเลิกได้ทุกเวลา · ไม่มีค่าธรรมเนียมแอบแฝง$$, NULL),
  ($$guide10Levels$$, $$10 levels$$, $$10 ລະດັບ$$, $$10 เลเวล$$, 'Guide'),
  ($$guideAddingSavings$$, $$💡 Adding savings$$, $$💡 ເພີ່ມເງິນອອມ$$, $$💡 เพิ่มเงินออม$$, 'Guide'),
  ($$guideAdvisorBody$$, $$Tap the 🤖 icon in the input bar on the home screen. The AI has access to your real transaction data and answers in Lao, Thai or English.$$, $$ແຕະໄອຄອນ 🤖 ໃນແຖບປ້ອນໜ້າຫຼັກ. AI ເຂົ້າເຖິງຂໍ້ມູນທຸລະກຳຈິງຂອງທ່ານ ແລະ ຕອບເປັນພາສາລາວ, ໄທ ຫຼື ອັງກິດ.$$, $$แตะไอคอน 🤖 ในแถบป้อนหน้าหลัก AI เข้าถึงข้อมูลรายการจริงของคุณ และตอบเป็นภาษาลาว, ไทย หรือ อังกฤษ$$, 'Guide'),
  ($$guideAdvisorQ1$$, $$"How much did I spend on food this month?"$$, $$"ເດືອນນີ້ໃຊ້ຈ່າຍອາຫານເທົ່າໃດ?"$$, $$"เดือนนี้ใช้จ่ายอาหารเท่าไหร่?"$$, 'Guide'),
  ($$guideAdvisorQ2$$, $$"Am I on track for my Bali goal?"$$, $$"ເປົ້າໝາຍ Bali ຢູ່ໃນເສັ້ນທາງບໍ?"$$, $$"เป้าหมาย Bali อยู่ในเส้นทางไหม?"$$, 'Guide'),
  ($$guideAdvisorQ3$$, $$"Which expense should I cut first?"$$, $$"ຄວນຫຼຸດລາຍຈ່າຍໃດກ່ອນ?"$$, $$"ควรลดรายจ่ายไหนก่อน?"$$, 'Guide'),
  ($$guideAdvisorQ4$$, $$"How much can I safely spend today?"$$, $$"ມື້ນີ້ໃຊ້ຈ່າຍໄດ້ອີກເທົ່າໃດ?"$$, $$"วันนี้ใช้จ่ายได้อีกเท่าไหร่?"$$, 'Guide'),
  ($$guideAdvisorTipPro$$, $$AI Advisor requires a Pro plan.$$, $$AI Advisor ຕ້ອງການແພັກ Pro.$$, $$AI Advisor ต้องใช้แพ็ก Pro$$, 'Guide'),
  ($$guideAnalyticsBody$$, $$The Analytics tab shows spending by category. Use the Today / Week / Month / All Time pills to filter. Use ← → to compare previous months.$$, $$ແຖບວິເຄາະສະແດງການໃຊ້ຈ່າຍຕາມໝວດ. ໃຊ້ປຸ່ມ ມື້ນີ້ / ອາທິດ / ເດືອນ / ທັງໝົດ ເພື່ອກັ່ນຕອງ. ໃຊ້ ← → ເພື່ອທຽບເດືອນກ່ອນ.$$, $$แถบวิเคราะห์แสดงการใช้จ่ายตามหมวด ใช้ปุ่ม วันนี้ / สัปดาห์ / เดือน / ทั้งหมด เพื่อกรอง ใช้ ← → เพื่อเทียบเดือนก่อน$$, 'Guide'),
  ($$guideAnalyticsTipMonth$$, $$The ▲▼ badge on each currency card shows if spending went up or down vs last month. Green ▼ = good. Red ▲ = went up.$$, $$ເຄື່ອງໝາຍ ▲▼ ໃນແຕ່ລະບັດສະກຸນເງິນສະແດງວ່າການໃຊ້ຈ່າຍເພີ່ມ ຫຼື ຫຼຸດທຽບກັບເດືອນກ່ອນ. ▼ ຂຽວ = ດີ. ▲ ແດງ = ເພີ່ມຂຶ້ນ.$$, $$เครื่องหมาย ▲▼ บนการ์ดสกุลเงินแสดงว่าการใช้จ่ายเพิ่มหรือลดเทียบกับเดือนก่อน ▼ เขียว = ดี ▲ แดง = เพิ่มขึ้น$$, 'Guide'),
  ($$guideAnalyticsTipRate$$, $$The % number in the Net card shows what portion of your income you kept. Aim for 20%+ as a healthy target.$$, $$ຕົວເລກ % ໃນບັດຍອດສຸດທິສະແດງວ່າທ່ານເກັບລາຍຮັບໄດ້ເທົ່າໃດ. ຕັ້ງເປົ້າ 20%+ ເປັນເປົ້າໝາຍທີ່ດີ.$$, $$ตัวเลข % ในการ์ดยอดสุทธิแสดงว่าคุณเก็บรายได้ไว้เท่าไหร่ ตั้งเป้า 20%+ เป็นเป้าหมายที่ดี$$, 'Guide'),
  ($$guideBestResults$$, $$💡 Best results$$, $$💡 ຜົນລັບທີ່ດີທີ່ສຸດ$$, $$💡 ผลลัพธ์ที่ดีที่สุด$$, 'Guide'),
  ($$guideBudgetBody$$, $$Go to the Budget tab. Tap any category and set a monthly limit. The bar fills as you spend — green is fine, orange is nearly there, red is over budget.$$, $$ໄປທີ່ແຖບງົບ. ແຕະໝວດໃດກໍໄດ້ແລ້ວຕັ້ງຂອບເຂດລາຍເດືອນ. ແຖບຈະເຕັມຂຶ້ນຕາມການໃຊ້ຈ່າຍ — ຂຽວ ດີ, ສົ້ມ ໃກ້ຮອດ, ແດງ ເກີນງົບ.$$, $$ไปที่แถบงบ แตะหมวดไหนก็ได้แล้วตั้งขีดจำกัดรายเดือน แถบจะเต็มขึ้นตามการใช้จ่าย — เขียว ดี, ส้ม ใกล้ถึง, แดง เกินงบ$$, 'Guide'),
  ($$guideBudgetTipCurrency$$, $$Budgets are per currency. Your Food limit in LAK is separate from your Food limit in THB.$$, $$ງົບແຍກຕາມສະກຸນເງິນ. ຂອບເຂດອາຫານໃນ LAK ແຍກຈາກຂອບເຂດອາຫານໃນ THB.$$, $$งบแยกตามสกุลเงิน ขีดจำกัดอาหารใน LAK แยกจากขีดจำกัดอาหารใน THB$$, 'Guide'),
  ($$guideBudgetTipSetting$$, $$Tap any category row → type an amount → Save. You can remove or change it anytime.$$, $$ແຕະແຖວໝວດໃດກໍໄດ້ → ພິມຈຳນວນ → ບັນທຶກ. ລຶບ ຫຼື ປ່ຽນໄດ້ທຸກເວລາ.$$, $$แตะแถวหมวดไหนก็ได้ → พิมพ์จำนวน → บันทึก ลบ หรือ เปลี่ยนได้ทุกเวลา$$, 'Guide'),
  ($$guideForSharedUse$$, $$💡 For shared use$$, $$💡 ສຳລັບໃຊ້ຮ່ວມກັນ$$, $$💡 สำหรับใช้ร่วมกัน$$, 'Guide'),
  ($$guideGoalsBody$$, $$Go to Goals → tap +. Give your goal a name, a target amount, and a deadline month. Phajot shows how much to save each month to get there.$$, $$ໄປທີ່ເປົ້າໝາຍ → ແຕະ +. ຕັ້ງຊື່ເປົ້າໝາຍ, ຈຳນວນເງິນ, ແລະ ເດືອນທີ່ຕ້ອງການ. Phajot ສະແດງວ່າຕ້ອງອອມເທົ່າໃດຕໍ່ເດືອນ.$$, $$ไปที่เป้าหมาย → แตะ + ตั้งชื่อเป้าหมาย, จำนวนเงิน, และเดือนที่ต้องการ Phajot แสดงว่าต้องออมเท่าไหร่ต่อเดือน$$, 'Guide'),
  ($$guideGoalsTipAdding$$, $$Tap "Add savings" on any goal card to record money set aside. The progress bar and timeline update instantly.$$, $$ແຕະ "ເພີ່ມເງິນອອມ" ໃນບັດເປົ້າໝາຍເພື່ອບັນທຶກເງິນທີ່ແຍກໄວ້. ແຖບຄວາມຄືບໜ້າ ແລະ ໄລຍະເວລາອັບເດດທັນທີ.$$, $$แตะ "เพิ่มเงินออม" บนการ์ดเป้าหมายเพื่อบันทึกเงินที่แยกไว้ แถบความคืบหน้าและไทม์ไลน์อัปเดตทันที$$, 'Guide'),
  ($$guideGoalsTipSmart$$, $$Phajot suggests which spending category to cut to reach your goal faster — look for the 💡 tip on the goal card.$$, $$Phajot ແນະນຳວ່າຄວນຫຼຸດໝວດໃດເພື່ອຮອດເປົ້າໝາຍໄວຂຶ້ນ — ຊອກຫາ 💡 ໃນບັດເປົ້າໝາຍ.$$, $$Phajot แนะนำว่าควรลดหมวดไหนเพื่อถึงเป้าหมายเร็วขึ้น — มองหา 💡 ในการ์ดเป้าหมาย$$, 'Guide'),
  ($$guideHowItWorks$$, $$How it works$$, $$ວິທີໃຊ້ງານ$$, $$วิธีใช้งาน$$, 'Guide'),
  ($$guideLockImmediately$$, $$Lock immediately$$, $$ລ໊ອກທັນທີ$$, $$ล็อกทันที$$, 'Guide'),
  ($$guideLogBody$$, $$Type what you spent in the bar at the bottom of the home screen. Just write naturally — Phajot reads the amount, currency and category automatically.$$, $$ພິมສິ່ງທີ່ໃຊ້ຈ່າຍໃນແຖບລຸ່ມສຸດຂອງໜ້າຫຼັກ. ພິມຕາມທຳມະຊາດ — Phajot ອ່ານຈຳນວນ, ສະກຸນເງິນ ແລະ ໝວດໃຫ້ອັດຕະໂນມັດ.$$, $$พิมพ์สิ่งที่ใช้จ่ายในแถบด้านล่างของหน้าหลัก พิมพ์ตามธรรมชาติ — Phajot อ่านจำนวน, สกุลเงิน และหมวดให้อัตโนมัติ$$, 'Guide'),
  ($$guideLogTipCurrency$$, $$No currency written? Phajot uses your base currency. You can always edit a transaction by tapping it in the list.$$, $$ບໍ່ໄດ້ຂຽນສະກຸນເງິນ? Phajot ໃຊ້ສະກຸນເງິນຫຼັກຂອງທ່ານ. ແກ້ໄຂລາຍການໄດ້ທຸກເວລາໂດຍແຕະໃນລາຍການ.$$, $$ไม่ได้เขียนสกุลเงิน? Phajot ใช้สกุลเงินหลักของคุณ แก้ไขรายการได้ทุกเวลาโดยแตะในรายการ$$, 'Guide'),
  ($$guideMilestoneBonuses$$, $$Milestone bonuses$$, $$ໂບນັສເປົ້າໝາຍ$$, $$โบนัสเป้าหมาย$$, 'Guide'),
  ($$guideMonthComparison$$, $$Month comparison$$, $$ທຽບເດືອນ$$, $$เทียบเดือน$$, 'Guide'),
  ($$guideOcrBody$$, $$Tap the 📷 icon in the input bar. Take a photo or pick from gallery. Phajot reads the total and saves it — you just confirm.$$, $$ແຕະໄອຄອນ 📷 ໃນແຖບປ້ອນ. ຖ່າຍຮູບ ຫຼື ເລືອກຈາກອັລບັ້ມ. Phajot ອ່ານຍອດລວມແລ້ວບັນທຶກໃຫ້ — ທ່ານພຽງຢືນຢັນ.$$, $$แตะไอคอน 📷 ในแถบป้อน ถ่ายรูป หรือ เลือกจากอัลบั้ม Phajot อ่านยอดรวมแล้วบันทึกให้ — คุณแค่ยืนยัน$$, 'Guide'),
  ($$guideOcrTipBest$$, $$Take the photo flat and well-lit. Make sure the total is visible. Works on restaurant bills, pharmacy receipts, and supermarket slips.$$, $$ຖ່າຍຮູບໃຫ້ແບນ ແລະ ແສງດີ. ໃຫ້ແນ່ໃຈວ່າເຫັນຍອດລວມ. ໃຊ້ໄດ້ກັບໃບບິນຮ້ານອາຫານ, ຮ້ານຂາຍຢາ, ແລະ ຊຸບເປີມາເກັດ.$$, $$ถ่ายรูปให้แบนและแสงดี ให้แน่ใจว่าเห็นยอดรวม ใช้ได้กับบิลร้านอาหาร, ร้านขายยา, และซูเปอร์มาร์เก็ต$$, 'Guide'),
  ($$guideOcrTipPro$$, $$Receipt scanning requires a Pro plan. Tap the 🔒 icon in the input bar to learn more.$$, $$ການສະແກນໃບບິນຕ້ອງການແພັກ Pro. ແຕະໄອຄອນ 🔒 ໃນແຖບປ້ອນເພື່ອສຶກສາເພີ່ມ.$$, $$การสแกนใบเสร็จต้องใช้แพ็ก Pro แตะไอคอน 🔒 ในแถบป้อนเพื่อดูเพิ่มเติม$$, 'Guide'),
  ($$guidePinBody$$, $$Go to Settings → Security. Set an Owner PIN for yourself and a Guest PIN for family. Both open the same account data — but guests cannot access Settings.$$, $$ໄປທີ່ການຕັ້ງຄ່າ → ຄວາມປອດໄພ. ຕັ້ງ PIN ເຈົ້າຂອງໃຫ້ຕົນເອງ ແລະ PIN ແຂກໃຫ້ຄອບຄົວ. ທັງສອງເປີດຂໍ້ມູນດຽວກັນ — ແຕ່ແຂກເຂົ້າການຕັ້ງຄ່າບໍ່ໄດ້.$$, $$ไปที่การตั้งค่า → ความปลอดภัย ตั้ง PIN เจ้าของให้ตัวเอง และ PIN แขกให้ครอบครัว ทั้งสองเปิดข้อมูลเดียวกัน — แต่แขกเข้าการตั้งค่าไม่ได้$$, 'Guide'),
  ($$guidePinTipLock$$, $$Settings → Security → "Lock app now" shows the PIN screen right away without closing the app.$$, $$ການຕັ້ງຄ່າ → ຄວາມປອດໄພ → "ລ໊ອກແອັບດຽວນີ້" ສະແດງໜ້າ PIN ທັນທີໂດຍບໍ່ປິດແອັບ.$$, $$การตั้งค่า → ความปลอดภัย → "ล็อกแอปตอนนี้" แสดงหน้า PIN ทันทีโดยไม่ปิดแอป$$, 'Guide'),
  ($$guidePinTipShared$$, $$Give your family member the Guest PIN. They can log transactions, view budgets and analytics — but cannot reset the app or change settings.$$, $$ໃຫ້ PIN ແຂກແກ່ສະມາຊິກຄອບຄົວ. ເຂົາສາມາດບັນທຶກລາຍການ, ເບິ່ງງົບ ແລະ ການວິເຄາະ — ແຕ່ຣີເຊັດແອັບ ຫຼື ປ່ຽນການຕັ້ງຄ່າບໍ່ໄດ້.$$, $$ให้ PIN แขกแก่สมาชิกครอบครัว เขาสามารถบันทึกรายการ, ดูงบและการวิเคราะห์ — แต่รีเซ็ตแอป หรือ เปลี่ยนการตั้งค่าไม่ได้$$, 'Guide'),
  ($$guideProFeature$$, $$Pro feature$$, $$ຟີເຈີ Pro$$, $$ฟีเจอร์ Pro$$, 'Guide'),
  ($$guideSafeBody$$, $$The strip at the top of the home screen shows how much you can still spend this month. It updates every time you log a transaction.$$, $$ແຖບດ້ານເທິງໜ້າຫຼັກສະແດງວ່າທ່ານໃຊ້ຈ່າຍໄດ້ອີກເທົ່າໃດໃນເດືອນນີ້. ອັບເດດທຸກຄັ້ງທີ່ບັນທຶກລາຍການ.$$, $$แถบด้านบนหน้าหลักแสดงว่าคุณใช้จ่ายได้อีกเท่าไหร่ในเดือนนี้ อัปเดตทุกครั้งที่บันทึกรายการ$$, 'Guide'),
  ($$guideSafeTipDisappears$$, $$This strip only shows when you have income logged for the current month. Log your salary first to see it.$$, $$ແຖບນີ້ສະແດງສະເພາະເມື່ອມີລາຍຮັບບັນທຶກໃນເດືອນນີ້. ບັນທຶກເງິນເດືອນກ່ອນເພື່ອເບິ່ງ.$$, $$แถบนี้แสดงเฉพาะเมื่อมีรายได้บันทึกในเดือนนี้ บันทึกเงินเดือนก่อนเพื่อดู$$, 'Guide'),
  ($$guideSafeTipFormula$$, $$Income this month minus what you've already spent minus what you need to save for your goals.$$, $$ລາຍຮັບເດືອນນີ້ ລົບ ສິ່ງທີ່ໃຊ້ຈ່າຍແລ້ວ ລົບ ສິ່ງທີ່ຕ້ອງອອມສຳລັບເປົ້າໝາຍ.$$, $$รายได้เดือนนี้ ลบ สิ่งที่ใช้จ่ายแล้ว ลบ สิ่งที่ต้องออมสำหรับเป้าหมาย$$, 'Guide'),
  ($$guideSavingsRate$$, $$💡 Savings rate$$, $$💡 ອັດຕາການປະຢັດ$$, $$💡 อัตราการออม$$, 'Guide'),
  ($$guideSettingLimit$$, $$💡 Setting a limit$$, $$💡 ການຕັ້ງຂອບເຂດ$$, $$💡 การตั้งขีดจำกัด$$, 'Guide'),
  ($$guideSmartSuggestion$$, $$💡 Smart suggestion$$, $$💡 ຄຳແນະນຳອັດສະລິຍະ$$, $$💡 คำแนะนำอัจฉริยะ$$, 'Guide'),
  ($$guideStreaksBody$$, $$Log at least one transaction every day to keep your streak. Each transaction gives +10 XP. Milestone streaks give bonus XP.$$, $$ບັນທຶກຢ່າງໜ້ອຍ 1 ລາຍການທຸກວັນເພື່ອຮັກສາວັນຕິດຕໍ່ກັນ. ແຕ່ລະລາຍການໄດ້ +10 XP. ເປົ້າໝາຍວັນຕິດຕໍ່ກັນໄດ້ໂບນັສ XP ເພີ່ມ.$$, $$บันทึกอย่างน้อย 1 รายการทุกวันเพื่อรักษาวันติดต่อกัน แต่ละรายการได้ +10 XP เป้าหมายวันติดต่อกันได้โบนัส XP เพิ่ม$$, 'Guide'),
  ($$guideStreaksTip$$, $$Tap the streak pill (📅 7d · Lv.2) in the top-right of the home screen to see your full progress card.$$, $$ແຕະປຸ່ມວັນຕິດຕໍ່ກັນ (📅 7d · Lv.2) ມຸมຂວາເທິງໜ້າຫຼັກເພື່ອເບິ່ງບັດຄວາມຄືບໜ້າ.$$, $$แตะปุ่มวันติดต่อกัน (📅 7d · Lv.2) มุมขวาบนหน้าหลักเพื่อดูการ์ดความคืบหน้า$$, 'Guide'),
  ($$guideStreaksTipLevels$$, $$🌱 Seedling → 🌿 Sprout → 🌳 Grower → 💚 Guardian → ⭐ Star → 🌟 Legend → 👑 Master → 🔥 Elite → 💎 Diamond → 🏆 Champion$$, $$🌱 ຕົ້ນກ້າ → 🌿 ໜໍ່ອ່ອນ → 🌳 ຜູ້ປູກ → 💚 ຜູ້ພິທັກ → ⭐ ດາວ → 🌟 ຕຳນານ → 👑 ມາສເຕີ້ → 🔥 ຊັ້ນຍອດ → 💎 ເພັດ → 🏆 ແຊ້ມ$$, $$🌱 ต้นกล้า → 🌿 หน่ออ่อน → 🌳 ผู้ปลูก → 💚 ผู้พิทักษ์ → ⭐ ดาว → 🌟 ตำนาน → 👑 มาสเตอร์ → 🔥 ชั้นยอด → 💎 เพชร → 🏆 แชมป์$$, 'Guide'),
  ($$guideStreaksTipMilestones$$, $$7 days +30 XP · 14 days +60 XP · 30 days +150 XP · 100 days +500 XP$$, $$7 ວັນ +30 XP · 14 ວັນ +60 XP · 30 ວັນ +150 XP · 100 ວັນ +500 XP$$, $$7 วัน +30 XP · 14 วัน +60 XP · 30 วัน +150 XP · 100 วัน +500 XP$$, 'Guide'),
