  ($$guideTopicStreaksTitle$$, $$Streaks & XP levels$$, $$ວັນຕິດຕໍ່ກັນ ແລະ ລະດັບ XP$$, $$วันติดต่อกัน และเลเวล XP$$, 'Guide'),
  ($$guideTryExamples$$, $$Try these examples$$, $$ລອງຕົວຢ່າງເຫຼົ່ານີ້$$, $$ลองตัวอย่างเหล่านี้$$, 'Guide'),
