  ($$registerTitle$$, $$Create your account$$, $$ສ້າງບັນຊີຂອງທ່ານ$$, $$สร้างบัญชีของคุณ$$, NULL),
  ($$registerPasswordHint$$, $$At least 6 characters$$, $$ຢ່າງໜ້ອຍ 6 ຕົວອັກສອນ$$, $$อย่างน้อย 6 ตัวอักษร$$, NULL),
  ($$registerPasswordConfirm$$, $$Confirm password$$, $$ຢືນຢັນລະຫັດຜ່ານ$$, $$ยืนยันรหัสผ่าน$$, NULL),
  ($$registerButton$$, $$Create account$$, $$ສ້າງບັນຊີ$$, $$สร้างบัญชี$$, NULL),
  ($$migrationTitle$$, $$Welcome back! 🐾$$, $$ຍິນດີຕ້ອນຮັບກັບມາ! 🐾$$, $$ยินดีต้อนรับกลับมา! 🐾$$, NULL),
  ($$migrationMessage$$, $$We've upgraded how passwords work. Please set a new password — you only need to do this once.$$, $$ພວກເຮົາໄດ້ອັບເກຣດວິທີການໃຊ້ລະຫັດຜ່ານ. ກະລຸນາຕັ້ງລະຫັດຜ່ານໃໝ່ — ທ່ານພຽງແຕ່ຕ້ອງເຮັດຄັ້ງດຽວ.$$, $$เราอัปเกรดวิธีการใช้รหัสผ่านแล้ว กรุณาตั้งรหัสผ่านใหม่ — ทำแค่ครั้งเดียวเท่านั้น$$, NULL),
  ($$migrationPrefilledHint$$, $$We'll use the password you just entered, or pick a new one.$$, $$ພວກເຮົາຈະໃຊ້ລະຫັດຜ່ານທີ່ທ່ານຫາກໍ່ປ້ອນ, ຫຼືເລືອກໃໝ່.$$, $$เราจะใช้รหัสผ่านที่คุณเพิ่งพิมพ์ หรือเลือกใหม่ก็ได้$$, NULL),
  ($$migrationNewPassword$$, $$New password$$, $$ລະຫັດຜ່ານໃໝ່$$, $$รหัสผ่านใหม่$$, NULL),
  ($$migrationConfirmPassword$$, $$Confirm new password$$, $$ຢືນຢັນລະຫັດຜ່ານໃໝ່$$, $$ยืนยันรหัสผ่านใหม่$$, NULL),
  ($$migrationContinue$$, $$Continue$$, $$ສືບຕໍ່$$, $$ต่อไป$$, NULL),
  ($$authWrongPassword$$, $$That password doesn't match. Give it another try?$$, $$ລະຫັດຜ່ານບໍ່ຖືກ. ລອງອີກຄັ້ງ?$$, $$รหัสผ่านไม่ถูกต้อง ลองอีกครั้งนะ$$, NULL),
  ($$authUnknownPhone$$, $$We don't have an account for that number. Try Create account instead?$$, $$ພວກເຮົາບໍ່ມີບັນຊີສຳລັບເບີນັ້ນ. ລອງສ້າງບັນຊີແທນ?$$, $$เราไม่มีบัญชีสำหรับเบอร์นี้ ลองสร้างบัญชีแทนไหม?$$, NULL),
  ($$passwordTooShort$$, $$Password needs at least 6 characters.$$, $$ລະຫັດຜ່ານຕ້ອງມີຢ່າງໜ້ອຍ 6 ຕົວອັກສອນ.$$, $$รหัสผ่านต้องมีอย่างน้อย 6 ตัวอักษร$$, NULL),
  ($$passwordMismatch$$, $$Those passwords don't match. Try again?$$, $$ລະຫັດຜ່ານບໍ່ກົງກັນ. ລອງອີກຄັ້ງ?$$, $$รหัสผ่านไม่ตรงกัน ลองใหม่นะ$$, NULL),
  ($$authForgotMessage$$, $$For now, Phajot is family-only. Please contact Kitty to reset your password.$$, $$ຕອນນີ້ Phajot ແມ່ນສຳລັບຄອບຄົວເທົ່ານັ້ນ. ກະລຸນາຕິດຕໍ່ Kitty ເພື່ອຣີເຊັດລະຫັດຜ່ານ.$$, $$ตอนนี้ Phajot เป็นแอปสำหรับครอบครัวเท่านั้น กรุณาติดต่อ Kitty เพื่อรีเซ็ตรหัสผ่าน$$, NULL),
  ($$authInvalidPhone$$, $$Please enter a valid phone number.$$, $$ກະລຸນາປ້ອນເບີໂທທີ່ຖືກຕ້ອງ.$$, $$กรุณากรอกเบอร์โทรที่ถูกต้อง$$, NULL),
  ($$authPhoneFormatError$$, $$That phone number doesn't look right. Check the format?$$, $$ເບີໂທບໍ່ຖືກຮູບແບບ. ກະລຸນາກວດສອບອີກຄັ້ງ?$$, $$เบอร์โทรไม่ถูกรูปแบบ ลองตรวจสอบอีกครั้ง?$$, NULL),
